// ==== detalhes_completo.js ====
function verDetalhesTransacao(transacaoId) {
    const modal = document.getElementById('modalDetalhesTransacao');
    const conteudo = document.getElementById('conteudoDetalhesTransacao');
    
    conteudo.innerHTML = `
        <div style="text-align: center; padding: 30px; color: var(--texto-mutado);">
            <div class="spinner-pure"></div>
            <p style="margin-top: 10px; font-size: var(--fs-micro);">Carregando dados da transação...</p>
        </div>
    `;
    
    modal.classList.add('active');
    
    fetch(`/financas/detalhes/${transacaoId}`)
        .then(response => response.json())
        .then(data => {
            if (data.error) {
                conteudo.innerHTML = `<div class="badge-pure bg-danger" style="width: 100%; padding: 10px;">${data.error}</div>`;
                return;
            }
            
            const tipoIcon = data.tipo === 'receita' ? '📈' : '📉';
            
            // ✅ CORRIGIDO: verifica se o elemento existe
            const tituloElement = document.getElementById('modalTituloTransacao');
            const tituloTexto = `${tipoIcon} ${data.descricao.substring(0, 50)}`;
            
            if (tituloElement) {
                tituloElement.innerHTML = tituloTexto;
            } else {
                // Fallback: cria o elemento no header
                const header = document.querySelector('.modal-detalhes-header');
                if (header) {
                    const span = document.createElement('span');
                    span.className = 'modal-detalhes-title';
                    span.id = 'modalTituloTransacao';
                    span.innerHTML = tituloTexto;
                    header.insertBefore(span, header.querySelector('.modal-detalhes-close'));
                }
            }
            
            conteudo.innerHTML = `
                <div class="modal-detalhes-field full-width" style="margin-bottom: 12px;">
                    <div class="field-detalhes-label" style="color: var(--cor-marca); font-weight: 600;">💰 Descrição</div>
                    <div class="field-detalhes-value-scroll" style="font-size: var(--fs-pequeno);">${data.descricao}</div>
                </div>
                
                <div class="modal-detalhes-grid" style="font-size: var(--fs-pequeno);">
                    <div class="modal-detalhes-field">
                        <div class="field-detalhes-label">📊 Tipo</div>
                        <div class="field-detalhes-value"><span class="badge-pure ${data.tipo === 'receita' ? 'bg-success' : 'bg-warning text-dark'}">${data.tipo_label}</span></div>
                    </div>

                    <div class="modal-detalhes-field">
                        <div class="field-detalhes-label">💰 Valor</div>
                        <div class="field-detalhes-value" style="font-weight: bold; font-size: 1.1rem;">${data.valor}</div>
                    </div>

                    <div class="modal-detalhes-field">
                        <div class="field-detalhes-label">📊 Status</div>
                        <div class="field-detalhes-value"><span class="badge-pure ${data.status === 'aberto' ? 'bg-danger' : 'bg-success'}">${data.status_label}</span></div>
                    </div>

                    <div class="modal-detalhes-field">
                        <div class="field-detalhes-label">🏷️ Categoria</div>
                        <div class="field-detalhes-value">
                            <span class="badge-pure" style="background-color: ${data.categoria_cor || 'var(--border-sutil)'}; color: white;">
                                ${data.categoria}
                            </span>
                        </div>
                    </div>

                    <div class="modal-detalhes-field">
                        <div class="field-detalhes-label">📅 Data Emissão</div>
                        <div class="field-detalhes-value">${data.data_emissao}</div>
                    </div>

                    <div class="modal-detalhes-field">
                        <div class="field-detalhes-label">⏰ Data Vencimento</div>
                        <div class="field-detalhes-value">${data.data_vencimento}</div>
                    </div>

                    <div class="modal-detalhes-field">
                        <div class="field-detalhes-label">✅ Data Quitação</div>
                        <div class="field-detalhes-value">${data.data_quitamento}</div>
                    </div>

                    <div class="modal-detalhes-field">
                        <div class="field-detalhes-label">📦 Parcela</div>
                        <div class="field-detalhes-value">${data.parcela_label}</div>
                    </div>
                </div>
            `;
        })
        .catch(error => {
            console.error('Erro:', error);
            conteudo.innerHTML = `<div class="badge-pure bg-danger" style="width: 100%; padding: 10px;">Erro ao carregar detalhes</div>`;
        });
}

function fecharModalDetalhesTransacao(event) {
    if (!event || event.target.classList.contains('modal-detalhes-overlay')) {
        document.getElementById('modalDetalhesTransacao').classList.remove('active');
    }
}

// Fechar modal com tecla ESC
document.addEventListener('keydown', function(event) {
    if (event.key === 'Escape') {
        const modal = document.getElementById('modalDetalhesTransacao');
        if (modal && modal.classList.contains('active')) {
            fecharModalDetalhesTransacao(null);
        }
    }
});

// ==== excluir_financas.js ====
// Sistema de Exclusão de Finanças - UNIFICADO
(function() {
    // ===== PARTE 1: CONFIGURA O MODAL =====
    function initModal() {
        const modal = document.getElementById("modalExcluirFinancas");
        if (!modal) return;
        
        if (!window.abrirModalExcluirFinancas) {
            window.abrirModalExcluirFinancas = function({ titulo, texto, onConfirm }) {
                const modalEl = document.getElementById("modalExcluirFinancas");
                const btnCancelar = document.getElementById("btnCancelarExcluirFinancas");
                const btnConfirmar = document.getElementById("btnConfirmarExcluirFinancas");
                const tituloEl = document.getElementById("modalExcluirTitulo");
                const textoEl = document.getElementById("modalExcluirTexto");

                if (!modalEl || !btnCancelar || !btnConfirmar) {
                    console.error('❌ Elementos do modal não encontrados');
                    if (window.Notificacao) window.Notificacao.erro('Erro ao carregar modal de exclusão');
                    return;
                }

                tituloEl.textContent = titulo;
                textoEl.textContent = texto;

                modalEl.classList.add('active');

                btnConfirmar.onclick = null;
                btnCancelar.onclick = null;
                modalEl.onclick = null;

                let bloqueio = false;

                btnConfirmar.onclick = async () => {
                    if (bloqueio) return;
                    bloqueio = true;
                    
                    const originalText = btnConfirmar.innerText;
                    btnConfirmar.innerText = "Processando...";

                    try {
                        if (onConfirm) await onConfirm();
                        modalEl.classList.remove('active');
                    } catch (error) {
                        if (error.message !== 'parcela_detectada') {
                            if (window.Notificacao) window.Notificacao.erro(error.message || 'Erro ao processar');
                        }
                    } finally {
                        btnConfirmar.innerText = originalText;
                        bloqueio = false;
                    }
                };

                btnCancelar.onclick = () => {
                    modalEl.classList.remove('active');
                };

                modalEl.onclick = (e) => {
                    if (e.target === modalEl) modalEl.classList.remove('active');
                };
            };
        }
    }
    
    // ===== PARTE 2: CONFIGURA OS BOTÕES =====
    function initBotoes() {
        document.querySelectorAll('.btn-excluir').forEach(btn => {
            btn.onclick = null;
            btn.addEventListener('click', handleExcluirClick);
        });
    }
    
    async function handleExcluirClick(e) {
        e.preventDefault();
        const btn = e.currentTarget;
        const id = btn.dataset.id;
        const descricao = btn.dataset.desc;

        if (typeof window.abrirModalExcluirFinancas === 'undefined') {
            console.error('❌ Modal não carregado');
            if (window.Notificacao) window.Notificacao.erro('Erro ao carregar modal de exclusão');
            return;
        }

        window.abrirModalExcluirFinancas({
            titulo: "Inativar Transação",
            texto: `Deseja inativar a transação: "${descricao}"?`,
            
            onConfirm: async () => {
                try {
                    btn.disabled = true;
                    btn.style.opacity = '0.5';
                    btn.innerHTML = '⏳';

                    const response = await fetch(`/financas/excluir/${id}`, {
                        method: "DELETE",
                        headers: {
                            'X-Requested-With': 'XMLHttpRequest',
                            'Content-Type': 'application/json'
                        }
                    });

                    const data = await response.json();

                    if (data.success) {
                        const linha = btn.closest('tr');
                        if (linha) {
                            linha.style.transition = 'opacity 0.3s, transform 0.3s';
                            linha.style.opacity = '0';
                            linha.style.transform = 'translateX(50px)';

                            setTimeout(() => {
                                linha.remove();
                                if (typeof calcularTotaisFinancas === 'function') {
                                    calcularTotaisFinancas();
                                }
                            }, 300);
                        }

                        if (window.Notificacao) window.Notificacao.sucesso(data.message || 'Transação inativada com sucesso!');

                    } else {
                        // CASO: É uma parcela
                        if (data.tipo_parcelamento === 'parcela') {
                            // Restaura o botão original
                            btn.disabled = false;
                            btn.style.opacity = '1';
                            btn.innerHTML = '<i class="bi bi-trash"></i>';
                            
                            // Fecha o modal atual
                            const modalEl = document.getElementById("modalExcluirFinancas");
                            if (modalEl) modalEl.classList.remove('active');
                            
                            // Limpa pendente anterior
                            window.parcelamentoPendente = null;
                            
                            // Delay para garantir que o modal anterior fechou
                            setTimeout(() => {
                                // Abre NOVO modal perguntando sobre inativar todas as parcelas
                                window.abrirModalExcluirFinancas({
                                    titulo: "⚠️ Atenção! Parcelamento Detectado",
                                    texto: `${data.mensagem}\n\nDeseja inativar TODAS as parcelas deste parcelamento?`,
                                    onConfirm: async () => {
                                        // Desabilita o botão original novamente
                                        btn.disabled = true;
                                        btn.style.opacity = '0.5';
                                        btn.innerHTML = '⏳';
                                        
                                        await excluirParcelamentoCompleto(data.transacao_pai_id, btn);
                                    }
                                });
                            }, 200);
                            
                            // Interrompe o fluxo do onConfirm
                            throw new Error('parcela_detectada');
                        }
                        
                        // CASO: É transação principal com parcelas
                        if (data.tipo_parcelamento === 'transacao_com_parcelas') {
                            // Restaura o botão original
                            btn.disabled = false;
                            btn.style.opacity = '1';
                            btn.innerHTML = '<i class="bi bi-trash"></i>';
                            
                            // Fecha o modal atual
                            const modalEl = document.getElementById("modalExcluirFinancas");
                            if (modalEl) modalEl.classList.remove('active');
                            
                            setTimeout(() => {
                                window.abrirModalExcluirFinancas({
                                    titulo: "⚠️ Atenção! Transação com Parcelas",
                                    texto: `${data.mensagem}\n\nDeseja inativar TODAS as parcelas?`,
                                    onConfirm: async () => {
                                        btn.disabled = true;
                                        btn.style.opacity = '0.5';
                                        btn.innerHTML = '⏳';
                                        await excluirParcelamentoCompleto(data.transacao_id, btn);
                                    }
                                });
                            }, 200);
                            
                            throw new Error('parcela_detectada');
                        }
                        
                        throw new Error(data.error);
                    }

                } catch (error) {
                    if (error.message !== 'parcela_detectada') {
                        if (window.Notificacao) window.Notificacao.erro(error.message || 'Erro ao inativar');
                        btn.disabled = false;
                        btn.style.opacity = '1';
                        btn.innerHTML = '<i class="bi bi-trash"></i>';
                    }
                }
            }
        });
    }
    
    // FUNÇÃO PARA EXCLUIR PARCELAMENTO COMPLETO
    async function excluirParcelamentoCompleto(transacaoPaiId, btnOriginal) {
        try {
            const response = await fetch(`/financas/excluir_parcelamento/${transacaoPaiId}`, {
                method: "DELETE",
                headers: {
                    'X-Requested-With': 'XMLHttpRequest',
                    'Content-Type': 'application/json'
                }
            });
            
            const data = await response.json();
            
            if (data.success) {
                if (window.Notificacao) window.Notificacao.sucesso(data.message || 'Parcelamento inativado com sucesso!');
                setTimeout(() => {
                    location.reload();
                }, 500);
            } else {
                throw new Error(data.error);
            }
        } catch (error) {
            if (window.Notificacao) window.Notificacao.erro(error.message || 'Erro ao inativar parcelamento');
            if (btnOriginal) {
                btnOriginal.disabled = false;
                btnOriginal.style.opacity = '1';
                btnOriginal.innerHTML = '<i class="bi bi-trash"></i>';
            }
        }
    }
    
    // ===== INICIALIZA =====
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', () => {
            initModal();
            initBotoes();
        });
    } else {
        initModal();
        initBotoes();
    }
})();

// ==== modal_estornar_quitado.js ====
// 🔥 PROTEÇÃO ANTI-DUPLICIDADE
if (!window._estornoSistemaCarregado) {
    window._estornoSistemaCarregado = true;
    
    (function() {
        console.log('✅ Sistema de estorno carregado');
        
        let modalAberto = false;
        
        // Função GLOBAL para abrir o modal
        window.abrirModalEstornar = function(config) {
            if (modalAberto) {
                console.log('⚠️ Modal já está aberto, ignorando...');
                return;
            }
            
            const modal = document.getElementById('modalEstornar');
            const titulo = document.getElementById('modalEstornarTitulo');
            const texto = document.getElementById('modalEstornarTexto');
            const btnConfirmar = document.getElementById('btnConfirmarEstornar');
            const btnCancelar = document.getElementById('btnCancelarEstornar');
            
            if (!modal) {
                console.error('❌ Modal não encontrado');
                window.Notificacao?.erro('Modal de estorno não encontrado');
                return;
            }
            
            console.log('✅ Abrindo modal de estorno...');
            modalAberto = true;
            
            // Configura textos
            titulo.textContent = config.titulo;
            texto.textContent = config.texto;
            
            // 🔥 USA CLASSE CSS
            modal.classList.add('active');
            
            // Remove eventos antigos
            btnConfirmar.onclick = null;
            btnCancelar.onclick = null;
            modal.onclick = null;
            
            // Função para fechar
            const fecharModal = () => {
                modal.classList.remove('active');
                modalAberto = false;
            };
            
            // Configura botão confirmar
            btnConfirmar.onclick = async function() {
                this.disabled = true;
                this.textContent = '⏳ Processando...';
                try {
                    await config.onConfirm(config.data);
                    fecharModal();
                } catch (error) {
                    console.error('Erro:', error);
                    window.Notificacao?.erro(error.message || 'Erro ao processar estorno');
                } finally {
                    this.disabled = false;
                    this.textContent = 'Confirmar Estorno';
                }
            };
            
            // Configura botão cancelar
            btnCancelar.onclick = fecharModal;
            
            // Fecha ao clicar fora
            modal.onclick = function(e) {
                if (e.target === modal) {
                    fecharModal();
                }
            };
        };
        
        // 🔥 Delegação de eventos - SÓ BLOQUEIA O MESMO BOTÃO
        const botoesProcessando = new Set();
        
        document.addEventListener('click', function(e) {
            const btn = e.target.closest('.btn-estornar');
            if (!btn) return;
            
            // 🔥 Se ESTE botão específico já está processando, ignora
            if (botoesProcessando.has(btn)) {
                console.log('⚠️ Este botão já está processando, ignorando...');
                return;
            }
            
            e.preventDefault();
            e.stopPropagation();
            
            // Marca este botão como "processando"
            botoesProcessando.add(btn);
            
            const id = btn.dataset.id;
            const descricao = btn.dataset.desc;
            const tipo = btn.dataset.tipo;
            const tipoTexto = tipo === 'despesa' ? 'DESPESA' : 'RECEITA';
            
            console.log('🔄 Estornar:', { id, descricao, tipo });
            
            window.abrirModalEstornar({
                titulo: `⚠️ Estornar ${tipoTexto}`,
                texto: `Deseja realmente ESTORNAR a transação?\n\n"${descricao}"\n\nEla voltará para o status ABERTO.`,
                data: { id, btn, descricao, tipo },
                
                onConfirm: async (data) => {
                    const { id, btn } = data;
                    btn.disabled = true;
                    btn.style.opacity = '0.5';
                    btn.innerHTML = '⏳';
                    
                    try {
                        const response = await fetch(`/estornar_transacao/${id}`, {
                            method: 'POST',
                            headers: {
                                'Content-Type': 'application/json',
                                'X-Requested-With': 'XMLHttpRequest'
                            }
                        });
                        
                        const result = await response.json();
                        
                        if (result.success) {
                            const linha = btn.closest('tr');
                            if (linha) {
                                linha.style.transition = 'opacity 0.3s';
                                linha.style.opacity = '0';
                                setTimeout(() => {
                                    linha.remove();
                                    if (typeof calcularTotaisFinancas === 'function') {
                                        calcularTotaisFinancas();
                                    }
                                }, 300);
                            }
                            window.Notificacao?.sucesso(result.message || 'Transação estornada com sucesso!');
                        } else {
                            throw new Error(result.error || 'Erro ao estornar');
                        }
                    } catch (error) {
                        console.error('❌ Erro:', error);
                        window.Notificacao?.erro(error.message || 'Erro ao estornar');
                        btn.disabled = false;
                        btn.style.opacity = '1';
                        btn.innerHTML = '<i class="bi bi-arrow-return-left"></i>';
                    } finally {
                        // 🔥 Libera ESTE botão específico
                        botoesProcessando.delete(btn);
                    }
                }
            });
            
            // Se o modal for fechado sem confirmar, libera o botão
            const observer = new MutationObserver(() => {
                const modal = document.getElementById('modalEstornar');
                if (modal && !modal.classList.contains('active')) {
                    botoesProcessando.delete(btn);
                    observer.disconnect();
                }
            });
            
            const modal = document.getElementById('modalEstornar');
            if (modal) {
                observer.observe(modal, { attributes: true, attributeFilter: ['class'] });
            }
        });
        
    })();
}

// ==== modal_reativar_inativo.js ====
// 🔥 PROTEÇÃO ANTI-DUPLICIDADE
if (!window._reativarSistemaCarregado) {
    window._reativarSistemaCarregado = true;
    
    (function() {
        console.log('✅ Sistema de reativação carregado');
        
        let modalAberto = false;
        
        // Função GLOBAL para abrir o modal
        window.abrirModalReativar = function(config) {
            if (modalAberto) {
                console.log('⚠️ Modal já está aberto, ignorando...');
                return;
            }
            
            const modal = document.getElementById('modalReativar');
            const titulo = document.getElementById('modalReativarTitulo');
            const texto = document.getElementById('modalReativarTexto');
            const btnConfirmar = document.getElementById('btnConfirmarReativar');
            const btnCancelar = document.getElementById('btnCancelarReativar');
            
            if (!modal) {
                console.error('❌ Modal não encontrado');
                window.Notificacao?.erro('Modal de reativação não encontrado');
                return;
            }
            
            console.log('✅ Abrindo modal de reativação...');
            modalAberto = true;
            
            titulo.textContent = config.titulo;
            texto.textContent = config.texto;
            modal.classList.add('active');
            
            btnConfirmar.onclick = null;
            btnCancelar.onclick = null;
            modal.onclick = null;
            
            const fecharModal = () => {
                modal.classList.remove('active');
                modalAberto = false;
            };
            
            btnConfirmar.onclick = async function() {
                this.disabled = true;
                this.textContent = '⏳ Processando...';
                try {
                    await config.onConfirm(config.data);
                    fecharModal();
                } catch (error) {
                    console.error('Erro:', error);
                    window.Notificacao?.erro(error.message || 'Erro ao processar reativação');
                } finally {
                    this.disabled = false;
                    this.textContent = 'Confirmar Reativação';
                }
            };
            
            btnCancelar.onclick = fecharModal;
            
            modal.onclick = function(e) {
                if (e.target === modal) {
                    fecharModal();
                }
            };
        };
        
        // Função para reativar
        async function executarReativacao(id, btn, isParcelamento = false) {
            const url = isParcelamento ? `/financas/reativar_parcelamento/${id}` : `/financas/reativar/${id}`;
            
            btn.disabled = true;
            btn.style.opacity = '0.5';
            btn.innerHTML = '⏳';
            
            try {
                const response = await fetch(url, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'X-Requested-With': 'XMLHttpRequest'
                    }
                });
                
                const result = await response.json();
                
                if (result.success) {
                    // 🔥 Se for parcelamento, recarrega a página (porque removeu várias linhas)
                    if (isParcelamento) {
                        window.Notificacao?.sucesso(result.message);
                        setTimeout(() => {
                            location.reload();  // Recarrega a página inteira
                        }, 1000);
                    } else {
                        // Transação simples: remove só a linha
                        const linha = btn.closest('tr');
                        if (linha) {
                            linha.style.transition = 'opacity 0.3s';
                            linha.style.opacity = '0';
                            setTimeout(() => {
                                linha.remove();
                                if (typeof calcularTotaisFinancas === 'function') {
                                    calcularTotaisFinancas();
                                }
                                window.Notificacao?.sucesso(result.message);
                            }, 300);
                        } else {
                            location.reload();
                        }
                    }
                } else {
                    throw new Error(result.error || 'Erro ao reativar');
                }
            } catch (error) {
                console.error('❌ Erro:', error);
                window.Notificacao?.erro(error.message);
                btn.disabled = false;
                btn.style.opacity = '1';
                btn.innerHTML = '<i class="bi bi-arrow-repeat"></i>';
            }
        }
                
        // Delegação de eventos
        const botoesProcessando = new Set();
        
        document.addEventListener('click', function(e) {
            const btn = e.target.closest('.btn-reativar');
            if (!btn) return;
            
            if (botoesProcessando.has(btn)) {
                console.log('⚠️ Este botão já está processando, ignorando...');
                return;
            }
            
            e.preventDefault();
            e.stopPropagation();
            
            botoesProcessando.add(btn);
            
            const id = btn.dataset.id;
            const descricao = btn.dataset.desc;
            
            console.log('🔄 Reativar:', { id, descricao });
            
            // 🔥 USA A ROTA DE VERIFICAÇÃO (GET)
            fetch(`/financas/verificar_reativacao/${id}`, {
                method: 'GET',  // <-- GET, não POST!
                headers: {
                    'Content-Type': 'application/json',
                    'X-Requested-With': 'XMLHttpRequest'
                }
            })
            .then(response => response.json())
            .then(data => {
                console.log('📦 Resposta da verificação:', data);
                
                if (data.tipo === 'parcelamento') {
                    window.abrirModalReativar({
                        titulo: '⚠️ Reativar Parcelamento',
                        texto: `${data.mensagem}\n\n"${data.descricao}"`,
                        data: { id, btn, isParcelamento: true },
                        onConfirm: async (data) => {
                            await executarReativacao(data.id, data.btn, true);
                            botoesProcessando.delete(btn);
                        }
                    });
                } 
                else if (data.tipo === 'parcela') {
                    // Abre modal perguntando se quer reativar o parcelamento completo
                    window.abrirModalReativar({
                        titulo: '⚠️ Reativar Parcelamento Completo',
                        texto: `${data.mensagem}\n\n"${data.descricao}"\n\nIsso vai reativar TODAS as ${data.total_parcelas} parcelas.`,
                        data: { id: data.transacao_pai_id, btn, isParcelamento: true },  // Usa o ID do pai
                        onConfirm: async (data) => {
                            await executarReativacao(data.id, data.btn, true);
                            botoesProcessando.delete(btn);
                        }
                    });
                }
                else if (data.tipo === 'simples') {
                    window.abrirModalReativar({
                        titulo: '⚠️ Reativar Transação',
                        texto: `Deseja realmente REATIVAR a transação?\n\n"${descricao}"`,
                        data: { id, btn, isParcelamento: false },
                        onConfirm: async (data) => {
                            await executarReativacao(data.id, data.btn, false);
                            botoesProcessando.delete(btn);
                        }
                    });
                }
                else {
                    window.Notificacao?.erro?.(data.error || 'Erro ao verificar');
                    botoesProcessando.delete(btn);
                }
            })
            .catch(error => {
                console.error('❌ Erro na verificação:', error);
                window.Notificacao?.erro('Erro ao verificar transação');
                botoesProcessando.delete(btn);
            });
        });
        
    })();
}

// ==== btn_quitar.js ====
function quitarTransacao(sequencia, botao) {
    
    const htmlOriginal = botao.innerHTML;
    botao.disabled = true;
    botao.style.opacity = '0.5';
    botao.innerHTML = '⏳';

    fetch('/quitar_transacao/' + sequencia, {
        method: 'POST',
        headers: {
            'X-Requested-With': 'XMLHttpRequest'
        }
    })
    .then(response => {
        return response.json();
    })
    .then(data => {
        
        if (data.success) {
            
            
            const linha = botao.closest('tr');
            
            // Atualiza o status na tabela (coluna 5)
            const celulaStatus = linha.querySelector('td:nth-child(5)');
            const tipoCelula = linha.querySelector('td:nth-child(2)');
            const ehReceita = tipoCelula.innerText.includes('Receita');
            
            let novoTipo = '';
            if (ehReceita) {
                celulaStatus.innerHTML = '<span class="badge-pure bg-success">💰 Recebido</span>';
                novoTipo = 'receita';
            } else {
                celulaStatus.innerHTML = '<span class="badge-pure bg-success">✅ Quitado</span>';
                novoTipo = 'despesa';
            }
            
            // Pega a célula de ações (última coluna)
            const celulaAcoes = linha.querySelector('td:last-child');
            
            // Remove botão de quitar
            botao.remove();
            
            // Remove botões de editar e excluir
            const btnEditar = celulaAcoes.querySelector('.edit');
            const btnExcluir = celulaAcoes.querySelector('.delete');
            if (btnEditar) btnEditar.remove();
            if (btnExcluir) btnExcluir.remove();
            
            // 🔥 ADICIONA O BOTÃO DE ESTORNAR
            const btnEstornar = document.createElement('button');
            btnEstornar.type = 'button';
            btnEstornar.className = 'btn-acao undo btn-estornar';
            btnEstornar.setAttribute('data-id', sequencia);
            btnEstornar.setAttribute('data-desc', data.descricao || 'Transação');
            btnEstornar.setAttribute('data-tipo', novoTipo);
            btnEstornar.title = 'Estornar';
            btnEstornar.innerHTML = '<i class="bi bi-arrow-return-left"></i>';
            
            // Adiciona o evento de click no botão estornar
            btnEstornar.addEventListener('click', function(e) {
                e.preventDefault();
                
                const id = this.dataset.id;
                const desc = this.dataset.desc;
                const tipo = this.dataset.tipo;
                const tipoTexto = tipo === 'despesa' ? 'DESPESA' : 'RECEITA';
                
                if (typeof window.abrirModalEstornar === 'undefined') {
                    alert('Erro: Sistema de estorno não carregado. Recarregue a página.');
                    return;
                }
                
                window.abrirModalEstornar({
                    titulo: `⚠️ Estornar ${tipoTexto}`,
                    texto: `Deseja realmente ESTORNAR a transação?\n\n"${desc}"\n\nEla voltará para o status ABERTO.`,
                    data: { id, btn: this, descricao: desc, tipo },
                    
                    onConfirm: async (data) => {
                        const { id, btn } = data;
                        
                        try {
                            btn.disabled = true;
                            btn.style.opacity = '0.5';
                            btn.innerHTML = '⏳';
                            
                            const response = await fetch(`/estornar_transacao/${id}`, {
                                method: 'POST',
                                headers: {
                                    'Content-Type': 'application/json',
                                    'X-Requested-With': 'XMLHttpRequest'
                                }
                            });
                            
                            const result = await response.json();
                            
                            if (result.success) {
                                const linha = btn.closest('tr');
                                if (linha) {
                                    linha.style.transition = 'opacity 0.3s';
                                    linha.style.opacity = '0';
                                    setTimeout(() => linha.remove(), 300);
                                }
                                
                                Notificacao.sucesso(result.message || 'Transação estornada!');
                                // 🔥 Recarrega só os dados, não a página inteira
                                setTimeout(() => location.reload(), 1000);
                            } else {
                                throw new Error(result.error || 'Erro ao estornar');
                            }
                        } catch (error) {
                            btn.disabled = false;
                            btn.style.opacity = '1';
                            btn.innerHTML = '<i class="bi bi-arrow-return-left"></i>';
                            Notificacao.erro(error.message);
                        }
                    }
                });
            });
            
            // Insere o botão estornar na célula de ações
            celulaAcoes.appendChild(btnEstornar);
            
            // Atualiza os totalizadores
            if (typeof calcularTotaisFinancas === 'function') {
                calcularTotaisFinancas();
            }
            
            Notificacao.sucesso('Transação quitada com sucesso!');
            
        } else {
            botao.disabled = false;
            botao.style.opacity = '1';
            botao.innerHTML = htmlOriginal;
            Notificacao.erro(data.error || 'Erro ao quitar transação');
        }
    })
    .catch(error => {
        botao.disabled = false;
        botao.style.opacity = '1';
        botao.innerHTML = htmlOriginal;
        Notificacao.erro('Erro de conexão. Tente novamente.');
    });
}

// ==== totalizadores.js ====
// totalizadores.js - VERSÃO COMPLETA E CORRIGIDA

function calcularTotaisFinancas() {
    const linhas = document.querySelector('.custom-table tbody')?.children || [];
    let totalReceitas = 0;
    let totalDespesas = 0;
    
    for (let i = 0; i < linhas.length; i++) {
        const linha = linhas[i];
        if (linha.querySelector('td[colspan]')) continue;
        
        const colunas = linha.cells;
        if (colunas.length < 3) continue;
        
        const tipo = colunas[1]?.innerText || '';
        const valorTexto = colunas[2]?.innerText || 'R$ 0,00';
        
        let valor = parseFloat(valorTexto.replace('R$', '').replace(/\./g, '').replace(',', '.').trim()) || 0;
        
        if (tipo.includes('Receita')) totalReceitas += valor;
        else if (tipo.includes('Despesa')) totalDespesas += valor;
    }
    
    const saldo = totalReceitas - totalDespesas;
    const formatar = (v) => `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;
    
    const elReceitas = document.getElementById('totalReceitas');
    const elDespesas = document.getElementById('totalDespesas');
    const elSaldo = document.getElementById('totalSaldo');
    
    if (elReceitas) elReceitas.innerHTML = formatar(totalReceitas);
    if (elDespesas) elDespesas.innerHTML = formatar(totalDespesas);
    if (elSaldo) elSaldo.innerHTML = formatar(saldo);
}

